import base64, hashlib, io, json
from openai import OpenAI
from PIL import Image

def b64(path, max_px=1024):
    img = Image.open(path); img.thumbnail((max_px, max_px), Image.LANCZOS)
    buf = io.BytesIO(); img.save(buf, format=img.format or "JPEG", quality=85)
    return base64.standard_b64encode(buf.getvalue()).decode(), buf.getvalue()

def extract_receipt(path):
    img_b64, raw = b64(path)
    key = hashlib.sha256(raw + b"document|gpt-4o").hexdigest()
    schema = ('{"store_name": str, "date": "YYYY-MM-DD", "items": [{"name": str, "qty": int, "price": float}],'
              ' "subtotal": float, "tax": float, "total": float}')
    prompt = (f"Extract: store_name, date, items, subtotal, tax, total. "
              f"Schema: {schema}. Use null for missing fields. Return JSON only.")
    for attempt in range(3):
        resp = OpenAI().chat.completions.create(model="gpt-4o", response_format={"type":"json_object"},
            messages=[{"role":"user","content":[{"type":"text","text":prompt},
                {"type":"image_url","image_url":{"url":f"data:image/jpeg;base64,{img_b64}","detail":"high"}}]}])
        try:
            fields = json.loads(resp.choices[0].message.content)
            return {"status":"ok","task":"document","fields":fields,"provider":"openai",
                    "model":"gpt-4o","cache_key":key,"cached":False,"retries":attempt}
        except json.JSONDecodeError as e:
            prompt = f"Previous response invalid JSON: {e}. Return ONLY JSON matching schema: {schema}"
    return {"status":"error","task":"document","fields":{},"provider":"openai",
            "model":"gpt-4o","cache_key":key,"cached":False,"retries":2,"error":"parse failed"}

print(json.dumps(extract_receipt("receipt.jpg"), indent=2))
